"""대화 컨텍스트 관리."""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


@dataclass
class Message:
    """단일 메시지."""

    role: str  # "system", "user", "assistant", "tool"
    content: str | None = None
    tool_calls: list[dict] | None = None
    tool_call_id: str | None = None
    name: str | None = None

    def to_dict(self) -> dict[str, Any]:
        d: dict[str, Any] = {"role": self.role}
        if self.content is not None:
            d["content"] = self.content
        if self.tool_calls:
            d["tool_calls"] = self.tool_calls
        if self.tool_call_id:
            d["tool_call_id"] = self.tool_call_id
        if self.name:
            d["name"] = self.name
        return d


class ConversationContext:
    """대화 메시지 목록 관리.

    멀티턴 대화의 메시지를 쌓고, LLM에 넘길 형태로 변환한다.
    """

    def __init__(self, system_prompt: str = ""):
        self._messages: list[Message] = []
        self._system_prompt = system_prompt

    @property
    def system_prompt(self) -> str:
        return self._system_prompt

    @system_prompt.setter
    def system_prompt(self, value: str):
        self._system_prompt = value

    def add_user(self, content: str) -> None:
        self._messages.append(Message(role="user", content=content))

    def add_assistant(self, content: str | None = None, tool_calls: list[dict] | None = None):
        self._messages.append(Message(role="assistant", content=content, tool_calls=tool_calls))

    def add_tool_result(self, tool_call_id: str, name: str, content: str) -> None:
        self._messages.append(
            Message(role="tool", content=content, tool_call_id=tool_call_id, name=name)
        )

    def to_messages(self) -> list[dict]:
        """LLM API에 넘길 messages 배열 생성."""
        msgs = []
        if self._system_prompt:
            msgs.append({"role": "system", "content": self._system_prompt})
        msgs.extend(m.to_dict() for m in self._messages)
        return msgs

    def load_messages(self, messages: list[dict]) -> None:
        """외부 대화 이력을 bulk 로드.

        각 dict는 OpenAI 메시지 형식: {"role": ..., "content": ..., ...}.
        기존 메시지 뒤에 추가된다.
        """
        for msg in messages:
            self._messages.append(Message(
                role=msg["role"],
                content=msg.get("content"),
                tool_calls=msg.get("tool_calls"),
                tool_call_id=msg.get("tool_call_id"),
                name=msg.get("name"),
            ))

    def inject_context(self, context_text: str, role: str = "system") -> None:
        """추가 컨텍스트를 메시지로 주입.

        RAG 검색 결과, 외부 문서 등을 대화에 삽입할 때 사용.
        """
        self._messages.append(Message(role=role, content=context_text))

    def clear(self) -> None:
        self._messages.clear()

    def __len__(self) -> int:
        return len(self._messages)
